def codec(strs):
    def encode(lst):
        return ''.join(f"{len(s)}#{s}" for s in lst)

    def decode(data):
        result = []
        i = 0
        while i < len(data):
            j = i
            while data[j] != '#':
                j += 1
            length = int(data[i:j])
            start = j + 1
            result.append(data[start:start + length])
            i = start + length
        return result

    return decode(encode(strs))
